1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const key = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (liveNeighbors: number): boolean =>
15	  liveNeighbors === 2 || liveNeighbors === 3;
16	
17	const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
18	  neighborsOf(cell).filter((n) => alive.has(key(n))).length;
19	
20	export function nextGeneration(liveCells: Cell[]): Cell[] {
21	  const alive = new Set(liveCells.map(key));
22	  const survivors = liveCells.filter((cell) => survives(countLiveNeighbors(cell, alive)));
23	  const candidates = new Map<string, Cell>();
24	  for (const cell of liveCells) {
25	    for (const n of neighborsOf(cell)) {
26	      if (!alive.has(key(n))) candidates.set(key(n), n);
27	    }
28	  }
29	  const births: Cell[] = [];
30	  for (const candidate of candidates.values()) {
31	    if (countLiveNeighbors(candidate, alive) === 3) births.push(candidate);
32	  }
33	  return [...survivors, ...births];
34	}
